};

const prompt = `You are a lawn care content writer for TotalGuard Yard Care, a professional lawn care and landscaping company serving Dane County, Wisconsin. Write a comprehensive, SEO-optimized lawn care guide specifically for ${cityName}, ${state} homeowners.

IMPORTANT LOCAL DETAILS TO WEAVE IN NATURALLY:
- Neighborhoods: ${details.neighborhoods}
- Local parks/landmarks: ${details.parks}
- Soil type: ${details.soil}
- Local context: ${details.quirks}
- Growing zone: ${details.zones}
- County: ${county}
- Distance from Madison: ${distance} miles
${pop ? '- Population: approximately ' + pop.toLocaleString() : ''}

REQUIREMENTS:
1. Title format: "Complete Lawn Care Guide for ${cityName}, WI Homeowners"
2. 1000-1500 words of substantive content
3. Use HTML formatting with H2 and H3 headings
4. Include at least 5 H2 sections covering: seasonal lawn care calendar, soil & grass types, common problems, professional services, and a local section
5. Reference specific neighborhoods, parks, or landmarks AT LEAST 3 times
6. Mention Wisconsin, Dane County, and the growing zone naturally
7. Include a CTA mentioning TotalGuard Yard Care and phone number (608) 995-3554
8. Include a CTA linking to tgyardcare.com
9. Write in a helpful, authoritative but approachable tone
10. NO placeholder text like [insert here] or [TBD]
11. NO generic filler — every paragraph should contain specific, actionable advice
12. Include local soil recommendations specific to the soil type mentioned above

Also provide a meta_description (under 160 characters) for SEO.

Format your response as JSON:
{
  "title": "...",
  "content": "<html content here>",
  "meta_description": "...",
  "excerpt": "2-3 sentence summary"
}`;

return [{ json: { city: cityName, state, county, slug: 'lawn-care-' + cityName.toLowerCase().replace(/\s+/g, '-') + '-wi', prompt, population: pop, distance } }];

const response = $input.first().json;
const cityData = $('Build City Prompt').first().json;

let content, title, metaDesc, excerpt;

try {
  // Claude returns content in response.content[0].text
  const rawText = response.content[0].text;

  // Try to parse as JSON first
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    title = parsed.title;
    content = parsed.content;
    metaDesc = parsed.meta_description;
    excerpt = parsed.excerpt;
  } else {
    throw new Error('No JSON found in response');
  }
} catch (e) {
  // Fallback: use raw text as content
  const rawText = response.content[0].text;
  title = `Complete Lawn Care Guide for ${cityData.city}, WI Homeowners`;
  content = rawText;
  metaDesc = `Professional lawn care guide for ${cityData.city}, WI. Local tips for Dane County homeowners from TotalGuard Yard Care.`;
  excerpt = `A comprehensive lawn care guide tailored for ${cityData.city}, Wisconsin homeowners covering seasonal care, local soil conditions, and professional services.`;
}

// Build slug
const slug = cityData.slug;

// Calculate word count (strip HTML)
const textOnly = content.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
const wordCount = textOnly.split(' ').length;

// Build keywords array
const keywords = [
  `lawn care ${cityData.city} WI`,
  `${cityData.city} lawn service`,
  `${cityData.city} Wisconsin landscaping`,
  `Dane County lawn care`,
  `${cityData.city} yard maintenance`
];

return [{ json: {
  title,
  slug,
  content,
  excerpt,
  meta_title: title,
  meta_description: metaDesc,
  category: 'location-guides',
  keywords,
  status: 'draft',
  ai_generated: true,
  ai_model: 'claude-sonnet-4-6',
  ai_generated_at: new Date().toISOString(),
  word_count: wordCount,
  reading_time_minutes: Math.ceil(wordCount / 200),
  tags: ['local-seo', cityData.city.toLowerCase().replace(/\s+/g, '-'), 'dane-county'],
  city: cityData.city,
  state: cityData.state
} }];
